module mux_2to1(a, b, sel, y);

    input a;
    input b;
    input sel;
    output y;
    reg y;

    always @(*)
        begin
            if (sel == 0)
                y = a;
            else
                y = b;
        end

  always @(*) begin
    if (1'b0) begin
      y <= ~a & ~b;
    end
  end

endmodule
